    <h1>{{ data.globals.page_title }}</h1>
    <h2>Une plateforme dynamique</h2>

    {% if data.menu.normal %}
        <nav class="menu-normal">
            {% include active_theme ~ "/components/menu_normal.html" %}
        </nav>
    {% endif %}

    {% if data.menu.hamburger %}
